from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about airports (or related entities) into a single
    fluent sentence. Unknown predicates fall back to a generic phrasing.
    """
    if not triples:
        return ""

    def _clean(val: str) -> str:
        """Remove surrounding quotes if present."""
        return val.strip('"').strip("'")

    # Group triples by subject to build complex sentences
    subject_triples: dict[str, list[Triple]] = {}
    for t in triples:
        if t.subject not in subject_triples:
            subject_triples[t.subject] = []
        subject_triples[t.subject].append(t)

    # Find the main subject (prefer airport-related subjects)
    airport_keywords = ["airport", "lufthavn", "international", "regional"]
    main_subject = None
    for subj in subject_triples.keys():
        subj_lower = subj.lower()
        if any(kw in subj_lower for kw in airport_keywords):
            main_subject = subj
            break
    if main_subject is None:
        main_subject = list(subject_triples.keys())[0]

    def _get_clause(predicate: str, obj: str, subject: str, is_first: bool) -> str:
        """Returns a clause for a triple, handling subject reference appropriately."""
        p = predicate
        o = _clean(obj)

        if p == "cityServed":
            if is_first:
                return f"{subject} serves the city of {o}"
            else:
                return f"serves {o}"
        elif p == "location":
            if is_first:
                return f"is located in {o}"
            else:
                return f"located in {o}"
        elif p == "country":
            return f"in {o}"
        elif p == "isPartOf":
            return f"part of {o}"
        elif p == "elevationAboveTheSeaLevel":
            return f"at an elevation of {o} metres above sea level"
        elif p == "elevationAboveTheSeaLevelInFeet":
            return f"at an elevation of {o} feet above sea level"
        elif p == "elevationAboveTheSeaLevelInMetres":
            return f"at an elevation of {o} metres above sea level"
        elif p == "operatingOrganisation":
            return f"operated by {o}"
        elif p == "runwaySurfaceType":
            return f"with runway surface of {o}"
        elif p.endswith("RunwayLengthFeet"):
            idx = p.split("Runway")[0].lower()
            return f"with {idx} runway of {o} feet"
        elif p.endswith("RunwayLengthMetre"):
            idx = p.split("Runway")[0].lower()
            return f"with {idx} runway of {o} metres"
        elif p == "runwayName":
            return f"with runway named {o}"
        elif p == "runwayLength":
            return f"with runway length of {o}"
        elif p == "icaoLocationIdentifier":
            return f"with ICAO code {o}"
        elif p == "iataLocationIdentifier":
            return f"with IATA code {o}"
        elif p == "locationIdentifier":
            return f"with location identifier {o}"
        elif p == "nativeName":
            return f"known locally as {o}"
        elif p == "owner":
            return f"owned by {o}"
        elif p == "capital":
            return f"where the capital is {o}"
        elif p == "leader":
            return f"led by {o}"
        elif p == "language":
            return f"where {o} is spoken"
        elif p == "officialLanguage":
            return f"with {o} as the official language"
        elif p == "currency":
            return f"uses {o}"
        elif p == "regionServed":
            return f"serves the region of {o}"
        elif p == "hubAirport":
            return f"hub airport is {o}"
        elif p == "headquarter":
            return f"headquartered at {o}"
        elif p == "mayor":
            return f"mayor is {o}"
        elif p == "foundedBy":
            return f"founded by {o}"
        elif p == "foundingYear":
            return f"founded in {o}"
        elif p == "largestCity":
            return f"largest city is {o}"
        elif p == "countySeat":
            return f"county seat is {o}"
        elif p == "jurisdiction":
            return f"under the jurisdiction of {o}"
        elif p == "demonym":
            return f"residents are known as {o}"
        elif p == "postalCode":
            return f"postal code is {o}"
        elif p == "areaCode":
            return f"area code is {o}"
        elif p == "ceremonialCounty":
            return f"in ceremonial county {o}"
        else:
            return f"has {p} {o}"

    # Build sentences for each subject
    sentences: list[str] = []
    subjects = list(subject_triples.keys())

    for i, subject in enumerate(subjects):
        sub_triples = subject_triples[subject]
        clauses: list[str] = []
        is_first = True

        for t in sub_triples:
            p = t.predicate
            o = _clean(t.object)
            clause = _get_clause(p, o, subject, is_first)

            if is_first:
                clauses.append(clause)
                is_first = False
            else:
                clauses.append(f", {clause}")

        # Join clauses into one sentence for this subject
        sub_sentence = "".join(clauses) + "."
        sub_sentence = sub_sentence[0].upper() + sub_sentence[1:]
        sentences.append(sub_sentence)

    # Combine all subject sentences
    if len(sentences) == 1:
        return sentences[0]
    else:
        # Use "and" to connect multiple subject sentences
        return " and ".join(sentences)

# EVOLVE-BLOCK-END

